import{_ as t,o as a,c as s,a3 as o}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"Release Process","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Release Process | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/release-process"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Release Process | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/release-process"}]]},"headers":[],"relativePath":"deployment/release-process.md","filePath":"deployment/release-process.md","lastUpdated":1784592367000}'),i={name:"deployment/release-process.md"};function r(n,e,l,d,c,h){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="release-process" tabindex="-1">Release Process <a class="header-anchor" href="#release-process" aria-label="Permalink to &quot;Release Process&quot;">​</a></h1><p>How SaleOS cuts coordinated platform releases across Backend, Frontend, and Docs.</p><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ol><li><strong>Three-repo sync</strong> — Backend, Frontend, and Docs ship the same platform tag when the release is platform-scoped.</li><li><strong>Docs first for intent</strong> — official release record lives under <code>docs/changelog/</code> before tags are created.</li><li><strong>CI green before tags</strong> — Quality Gate (+ Tests on Backend) must pass on the release SHA in each repo.</li><li><strong>No production reseeding</strong> — upgrades are migrate-only (<a href="./upgrade">Upgrade Guide</a>).</li><li><strong>Freeze rules still apply</strong> — do not redesign Authentication, Tenancy, RBAC licensing, Billing, Marketplace, Settings, or Gateway architecture (<a href="/getting-started/platform-freeze">Platform Freeze</a>).</li></ol><h2 id="tag-naming-semantic-versioning" tabindex="-1">Tag naming (Semantic Versioning) <a class="header-anchor" href="#tag-naming-semantic-versioning" aria-label="Permalink to &quot;Tag naming (Semantic Versioning)&quot;">​</a></h2><p>Use <strong>clean</strong> SemVer tags only:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Example</th><th>Use</th></tr></thead><tbody><tr><td><code>vMAJOR.MINOR.PATCH</code></td><td><code>v1.1.0</code></td><td>Coordinated platform release</td></tr></tbody></table><p><strong>Do not</strong> use suffixes such as <code>-platform</code>, <code>-stable</code>, <code>-release</code>, or <code>-rc</code> on production GA tags.</p><p>Version selection:</p><ul><li>If the intended version has <strong>never been tagged</strong> in git → use that version (e.g. first tag is <code>v1.1.0</code>).</li><li>If <code>vX.Y.Z</code> <strong>already exists</strong> as a tag → bump appropriately (<code>vX.Y.Z+1</code> patch or next minor).</li></ul><h3 id="current-line" tabindex="-1">Current line <a class="header-anchor" href="#current-line" aria-label="Permalink to &quot;Current line&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tag</th><th>Meaning</th></tr></thead><tbody><tr><td><code>v1.1.0</code></td><td>First official platform release — see <a href="/changelog/v1.1.0">v1.1.0</a></td></tr></tbody></table><h2 id="branch-protection-repository-admins" tabindex="-1">Branch protection (repository admins) <a class="header-anchor" href="#branch-protection-repository-admins" aria-label="Permalink to &quot;Branch protection (repository admins)&quot;">​</a></h2><p>Do not automate branch protection from CI. After Quality Gates exist on <code>main</code>, require:</p><table tabindex="0"><thead><tr><th>Repository</th><th>Required status checks</th></tr></thead><tbody><tr><td><strong>SaaS-Backend</strong></td><td><code>Quality Gate (PHP 8.4)</code>, <code>Pest (PHP 8.4)</code></td></tr><tr><td><strong>SaaS-Frontend</strong></td><td><code>Quality Gate (Node LTS)</code></td></tr><tr><td><strong>SaaS-Docs</strong></td><td><code>Quality Gate (VitePress)</code></td></tr></tbody></table><p>Also recommended: require PRs, dismiss stale reviews, block force-push to <code>main</code>.</p><h2 id="pre-release-checklist" tabindex="-1">Pre-release checklist <a class="header-anchor" href="#pre-release-checklist" aria-label="Permalink to &quot;Pre-release checklist&quot;">​</a></h2><ul><li>[ ] Release notes page under <code>/changelog/vX.Y.Z</code></li><li>[ ] Delivery notes on <a href="/changelog/">Changelog</a> updated</li><li>[ ] Upgrade / runbook deltas documented</li><li>[ ] Backend: Larastan 0, Pest green, Quality Gate green</li><li>[ ] Frontend: lint, typecheck, unit, build green</li><li>[ ] Docs: VitePress build green (dead links fail the build)</li><li>[ ] Staging smoke: auth, mail test, one module path</li><li>[ ] Package versions bumped where applicable (<code>package.json</code>)</li></ul><h2 id="cutting-the-release" tabindex="-1">Cutting the release <a class="header-anchor" href="#cutting-the-release" aria-label="Permalink to &quot;Cutting the release&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># On each repo, on the agreed production SHA on main:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tag</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v1.1.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Platform release v1.1.0&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Only after CI is green on main:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v1.1.0</span></span></code></pre></div><p>Then create a GitHub Release on each repo whose body links to the Docs release page.</p><p>Recommended order: <strong>Backend → Frontend → Docs</strong>.</p><h2 id="post-release" tabindex="-1">Post-release <a class="header-anchor" href="#post-release" aria-label="Permalink to &quot;Post-release&quot;">​</a></h2><ol><li>Deploy Backend using <a href="./platform-production-runbook">Production Runbook</a></li><li>Deploy Frontend build-artifacts / Forge SPA per project norms</li><li>Deploy Docs build-artifacts</li><li>Run <a href="./upgrade">Upgrade Guide</a> steps on existing environments</li><li>Verify <code>/up</code>, mail test, queue <code>emails,default</code>, Reverb if used</li></ol><h2 id="changelog-ownership" tabindex="-1">Changelog ownership <a class="header-anchor" href="#changelog-ownership" aria-label="Permalink to &quot;Changelog ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Owner</th></tr></thead><tbody><tr><td>VitePress <code>docs/changelog/</code></td><td>Product / Docs — canonical narrative</td></tr><tr><td>Backend <code>.github/workflows/release.yml</code></td><td>Optional auto-append to repo <code>CHANGELOG.md</code> on GitHub Release publish</td></tr></tbody></table><p>Every feature, fix, or ops change should update Docs in the <strong>same PR</strong> as code — see <a href="/developer-guide/documentation-governance">Documentation Governance</a>.</p><h2 id="what-not-to-do" tabindex="-1">What not to do <a class="header-anchor" href="#what-not-to-do" aria-label="Permalink to &quot;What not to do&quot;">​</a></h2><ul><li>Tag without green CI on <code>main</code></li><li>Tag only one repo for a platform-scoped release</li><li>Claim a tag exists in Docs before <code>git push</code> of the tag</li><li>Use suffix tags (<code>-platform</code>, etc.) for GA</li><li>Run <code>db:seed</code> as part of a production upgrade</li></ul>`,29)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
